export function lookupSchoolLogo(query: string): string | null {
  const q = query.toLowerCase().trim();
  if (!q) return null;
  const match = schools.find(s =>
    s.s.toLowerCase() === q ||
    s.a.toLowerCase() === q ||
    s.n.some(n => n.toLowerCase() === q || q.includes(n.toLowerCase()) || n.toLowerCase().includes(q)) ||
    s.s.toLowerCase().includes(q) ||
    q.includes(s.s.toLowerCase())
  );
  if (match) return `http://a.espncdn.com/i/teamlogos/ncaa/500/${match.i}.png`;
  return null;
}